/* Suggested markup: <div class="uiwiki-native-snap-feature-rail" tabindex="0"><span>Native Snap Feature Rail</span></div> */
.uiwiki-native-snap-feature-rail {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-native-snap-feature-rail > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: native_snap_feature_rail 1.8s ease-in-out infinite alternate;
}
.uiwiki-native-snap-feature-rail:hover,
.uiwiki-native-snap-feature-rail:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes native_snap_feature_rail {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-native-snap-feature-rail, .uiwiki-native-snap-feature-rail > span { animation: none; transition: none; }
}
